refsection.programlisting:
volume = zeros(24, 24, 8) == 1;
volume(5:18, 5:18, 3:6) = %t;
volume(2, 2, 2) = %t;
clean = imbwareaopen3(volume, 20);
imshow(max(clean, 3));

volume = zeros(32, 32, 12) == 1;
volume(8:24, 8:24, 4:9) = %t;
volume(2:3, 2:3, 2:3) = %t;
